t.script:

var selectedBlock = "logo";
var dragging = null;

var varsByBlock = {
    logo: {
        x: "--logo-x",
        y: "--logo-y",
        w: "--logo-w",
        h: "--logo-h",
        font: null
    },
    data: {
        x: "--data-x",
        y: "--data-y",
        w: "--data-w",
        h: "--data-h",
        font: "--data-font"
    },
    contact: {
        x: "--contact-x",
        y: "--contact-y",
        w: "--contact-w",
        h: "--contact-h",
        font: "--contact-font"
    },
    qr: {
        x: "--qr-x",
        y: "--qr-y",
        w: "--qr-w",
        h: "--qr-h",
        font: "--qr-title-font"
    },
    qrtext: {
        x: "--qrtext-x",
        y: "--qrtext-y",
        w: "--qrtext-w",
        h: "--qrtext-h",
        font: "--qrtext-font"
    },
    divider: {
        x: "--divider-x",
        y: "--divider-y",
        w: "--divider-w",
        h: "--divider-h",
        font: null
    }
};

function rootStyle() {
    return getComputedStyle(document.documentElement);
}

function setCssVar(name, value) {
    document.documentElement.style.setProperty(name, value);
}

function getCssVarNumber(name) {
    var value = rootStyle().getPropertyValue(name).trim();
    return parseFloat(value.replace("%", "").replace("px", "").replace("mm", ""));
}

function getValue(id, fallback) {
    var el = document.getElementById(id);
    if (!el) {
        return fallback;
    }
    return el.value || fallback;
}

function setValue(id, value) {
    var el = document.getElementById(id);
    if (el) {
        el.value = value;
    }
}

function setDynamicPageStyle(orientation) {
    var style = document.getElementById("dynamicPrintPageStyle");
    if (!style) {
        return;
    }

    if (orientation === "portrait") {
        style.textContent =
            "@page { size: A4 portrait; margin: 0; }" +
            "@media print { @page { size: A4 portrait; margin: 0; } }";
    } else {
        style.textContent =
            "@page { size: A4 landscape; margin: 0; }" +
            "@media print { @page { size: A4 landscape; margin: 0; } }";
    }
}

function markManual() {
    setValue("presetInput", "manual");
}

function manualConfig() {
    markManual();
    applyConfig();
}

function applyOrientation(orientation) {
    setDynamicPageStyle(orientation);

    if (orientation === "portrait") {
        setCssVar("--sheet-width", "210mm");
        setCssVar("--sheet-height", "297mm");
        setValue("scaleInput", "0.80");
    } else {
        setCssVar("--sheet-width", "297mm");
        setCssVar("--sheet-height", "210mm");
        setValue("scaleInput", "0.90");
    }

    applyPreset("maximo");
}

function applyPreset(preset) {
    var orientation = getValue("orientationInput", "landscape");

    if (preset === "maximo") {
        setValue("sheetPaddingInput", "1");
        setValue("sheetGapInput", "1.5");

        if (orientation === "landscape") {
            setValue("qrSizeInput", "42");
            setLayoutLandscapeMax();
        } else {
            setValue("qrSizeInput", "35");
            setLayoutPortraitMax();
        }
    }

    if (preset === "grande") {
        setValue("sheetPaddingInput", "2");
        setValue("sheetGapInput", "2");

        if (orientation === "landscape") {
            setValue("qrSizeInput", "40");
            setLayoutLandscapeLarge();
        } else {
            setValue("qrSizeInput", "33");
            setLayoutPortraitLarge();
        }
    }

    if (preset === "mediano") {
        setValue("sheetPaddingInput", "4");
        setValue("sheetGapInput", "4");

        if (orientation === "landscape") {
            setValue("qrSizeInput", "36");
            setLayoutLandscapeMedium();
        } else {
            setValue("qrSizeInput", "31");
            setLayoutPortraitMedium();
        }
    }

    if (preset === "compacto") {
        setValue("sheetPaddingInput", "5");
        setValue("sheetGapInput", "5");

        if (orientation === "landscape") {
            setValue("qrSizeInput", "32");
            setLayoutLandscapeCompact();
        } else {
            setValue("qrSizeInput", "28");
            setLayoutPortraitCompact();
        }
    }

    applyConfig();
    selectBlock(selectedBlock);
}

function applyConfig() {
    var scale = getValue("scaleInput", "0.90");
    var pad = getValue("sheetPaddingInput", "1");
    var gap = getValue("sheetGapInput", "1.5");
    var qrSize = getValue("qrSizeInput", "42");

    setCssVar("--screen-scale", scale);
    setCssVar("--sheet-padding", pad + "mm");
    setCssVar("--sheet-gap", gap + "mm");
    setCssVar("--qr-size", qrSize + "mm");
}

function setLayoutLandscapeMax() {
    setBlock("logo", 5, 7, 44, 30);
    setBlock("data", 5, 39, 50, 20);
    setBlock("contact", 5, 70, 50, 24);
    setBlock("divider", 59, 7, 0.2, 86);
    setBlock("qr", 65, 6, 30, 58);
    setBlock("qrtext", 64, 66, 32, 28);
    setCssVar("--data-font", "13px");
    setCssVar("--contact-font", "10.5px");
    setCssVar("--qrtext-font", "9.5px");
    setCssVar("--qr-title-font", "9px");
}

function setLayoutLandscapeLarge() {
    setBlock("logo", 6, 8, 42, 28);
    setBlock("data", 5, 40, 50, 19);
    setBlock("contact", 5, 70, 50, 23);
    setBlock("divider", 59, 8, 0.2, 84);
    setBlock("qr", 66, 7, 29, 56);
    setBlock("qrtext", 65, 66, 31, 27);
    setCssVar("--data-font", "12px");
    setCssVar("--contact-font", "10px");
    setCssVar("--qrtext-font", "9px");
    setCssVar("--qr-title-font", "8.5px");
}

function setLayoutLandscapeMedium() {
    setBlock("logo", 8, 9, 38, 25);
    setBlock("data", 5, 39, 50, 20);
    setBlock("contact", 5, 69, 50, 24);
    setBlock("divider", 59, 9, 0.2, 82);
    setBlock("qr", 67, 8, 27, 53);
    setBlock("qrtext", 66, 66, 29, 26);
    setCssVar("--data-font", "11px");
    setCssVar("--contact-font", "9px");
    setCssVar("--qrtext-font", "8px");
    setCssVar("--qr-title-font", "8px");
}

function setLayoutLandscapeCompact() {
    setBlock("logo", 10, 10, 34, 22);
    setBlock("data", 5, 39, 48, 18);
    setBlock("contact", 5, 69, 48, 22);
    setBlock("divider", 59, 10, 0.2, 80);
    setBlock("qr", 68, 10, 25, 49);
    setBlock("qrtext", 66, 66, 29, 24);
    setCssVar("--data-font", "10px");
    setCssVar("--contact-font", "8px");
    setCssVar("--qrtext-font", "7.5px");
    setCssVar("--qr-title-font", "7.5px");
}

function setLayoutPortraitMax() {
    setBlock("logo", 7, 8, 42, 25);
    setBlock("data", 5, 38, 50, 18);
    setBlock("contact", 5, 69, 50, 23);
    setBlock("divider", 59, 8, 0.2, 84);
    setBlock("qr", 66, 8, 28, 50);
    setBlock("qrtext", 65, 63, 30, 30);
    setCssVar("--data-font", "11px");
    setCssVar("--contact-font", "9px");
    setCssVar("--qrtext-font", "8px");
    setCssVar("--qr-title-font", "8px");
}

function setLayoutPortraitLarge() {
    setBlock("logo", 8, 9, 40, 24);
    setBlock("data", 5, 39, 50, 17);
    setBlock("contact", 5, 69, 50, 23);
    setBlock("divider", 59, 9, 0.2, 82);
    setBlock("qr", 66, 9, 28, 49);
    setBlock("qrtext", 65, 64, 30, 28);
    setCssVar("--data-font", "10.5px");
    setCssVar("--contact-font", "8.5px");
    setCssVar("--qrtext-font", "7.8px");
    setCssVar("--qr-title-font", "7.8px");
}

function setLayoutPortraitMedium() {
    setBlock("logo", 10, 10, 36, 22);
    setBlock("data", 5, 39, 49, 17);
    setBlock("contact", 5, 69, 49, 22);
    setBlock("divider", 59, 10, 0.2, 80);
    setBlock("qr", 67, 10, 26, 47);
    setBlock("qrtext", 65, 64, 30, 27);
    setCssVar("--data-font", "10px");
    setCssVar("--contact-font", "8px");
    setCssVar("--qrtext-font", "7.5px");
    setCssVar("--qr-title-font", "7.5px");
}

function setLayoutPortraitCompact() {
    setBlock("logo", 11, 11, 34, 20);
    setBlock("data", 5, 39, 48, 16);
    setBlock("contact", 5, 69, 48, 21);
    setBlock("divider", 59, 11, 0.2, 78);
    setBlock("qr", 68, 11, 24, 44);
    setBlock("qrtext", 65, 64, 30, 26);
    setCssVar("--data-font", "9px");
    setCssVar("--contact-font", "7.5px");
    setCssVar("--qrtext-font", "7px");
    setCssVar("--qr-title-font", "7px");
}

function setBlock(block, x, y, w, h) {
    var cfg = varsByBlock[block];
    if (!cfg) {
        return;
    }

    if (block === "divider") {
        setCssVar(cfg.x, x + "%");
        setCssVar(cfg.y, y + "%");
        setCssVar(cfg.w, Math.max(1, w) + "px");
        setCssVar(cfg.h, h + "%");
    } else {
        setCssVar(cfg.x, x + "%");
        setCssVar(cfg.y, y + "%");
        setCssVar(cfg.w, w + "%");
        setCssVar(cfg.h, h + "%");
    }
}

function selectBlock(block) {
    selectedBlock = block;
    setValue("blockInput", block);

    document.querySelectorAll(".block").forEach(function (el) {
        if (el.getAttribute("data-block") === block) {
            el.classList.add("selected-block");
        } else {
            el.classList.remove("selected-block");
        }
    });

    loadSelectedToInputs();
}

function loadSelectedToInputs() {
    var cfg = varsByBlock[selectedBlock];
    if (!cfg) {
        return;
    }

    setValue("xInput", getCssVarNumber(cfg.x));
    setValue("yInput", getCssVarNumber(cfg.y));
    setValue("wInput", getCssVarNumber(cfg.w));
    setValue("hInput", getCssVarNumber(cfg.h));

    if (cfg.font) {
        setValue("fontInput", getCssVarNumber(cfg.font));
    }
}

function updateSelectedFromInputs() {
    markManual();

    var x = parseFloat(getValue("xInput", "0"));
    var y = parseFloat(getValue("yInput", "0"));
    var w = parseFloat(getValue("wInput", "10"));
    var h = parseFloat(getValue("hInput", "10"));

    if (isNaN(x)) { x = 0; }
    if (isNaN(y)) { y = 0; }
    if (isNaN(w)) { w = 10; }
    if (isNaN(h)) { h = 10; }

    x = Math.max(0, Math.min(99, x));
    y = Math.max(0, Math.min(99, y));
    w = Math.max(1, Math.min(100 - x, w));
    h = Math.max(1, Math.min(100 - y, h));

    setBlock(selectedBlock, x, y, w, h);
    loadSelectedToInputs();
}

function updateSelectedFont() {
    markManual();

    var cfg = varsByBlock[selectedBlock];
    if (!cfg || !cfg.font) {
        return;
    }

    var font = parseFloat(getValue("fontInput", "12"));
    if (isNaN(font)) {
        font = 12;
    }

    setCssVar(cfg.font, font + "px");
}

function resetDesigner() {
    setValue("orientationInput", "landscape");
    setDynamicPageStyle("landscape");
    setCssVar("--sheet-width", "297mm");
    setCssVar("--sheet-height", "210mm");
    setValue("presetInput", "maximo");
    setValue("scaleInput", "0.90");
    applyPreset("maximo");
    selectBlock("logo");
}

function exportPdf() {
    var orientation = getValue("orientationInput", "landscape");
    setDynamicPageStyle(orientation);
    applyConfig();

    setTimeout(function () {
        window.print();
    }, 250);
}

function initDragging() {
    document.querySelectorAll(".block").forEach(function (el) {
        el.addEventListener("mousedown", function (ev) {
            var block = el.getAttribute("data-block");
            selectBlock(block);

            var isResize = ev.target.classList.contains("resize-dot");
            var sticker = el.closest(".sticker");
            var rect = sticker.getBoundingClientRect();
            var cfg = varsByBlock[block];

            dragging = {
                block: block,
                mode: isResize ? "resize" : "move",
                startX: ev.clientX,
                startY: ev.clientY,
                rect: rect,
                x: getCssVarNumber(cfg.x),
                y: getCssVarNumber(cfg.y),
                w: getCssVarNumber(cfg.w),
                h: getCssVarNumber(cfg.h)
            };

            ev.preventDefault();
            ev.stopPropagation();
        });
    });

    document.addEventListener("mousemove", function (ev) {
        if (!dragging) {
            return;
        }

        var dx = ((ev.clientX - dragging.startX) / dragging.rect.width) * 100;
        var dy = ((ev.clientY - dragging.startY) / dragging.rect.height) * 100;

        var x = dragging.x;
        var y = dragging.y;
        var w = dragging.w;
        var h = dragging.h;

        if (dragging.mode === "move") {
            x = dragging.x + dx;
            y = dragging.y + dy;
        } else {
            w = dragging.w + dx;
            h = dragging.h + dy;
        }

        x = Math.max(0, Math.min(99, x));
        y = Math.max(0, Math.min(99, y));
        w = Math.max(1, Math.min(100 - x, w));
        h = Math.max(1, Math.min(100 - y, h));

        setBlock(dragging.block, x, y, w, h);
        loadSelectedToInputs();
        markManual();
    });

    document.addEventListener("mouseup", function () {
        dragging = null;
    });
}

document.addEventListener("DOMContentLoaded", function () {
    setDynamicPageStyle("landscape");
    applyPreset("maximo");
    selectBlock("logo");
    initDragging();
});
